BANK_B64 = """"""

def now_iso():
    return datetime.now(timezone.utc).isoformat()

def n(value):
    if pd.isna(value):
        return ""
    return str(value).strip()

def hp(password, salt):
    return hashlib.sha256((salt + password).encode("utf-8")).hexdigest()

def default_store():
    def u(uid, name, pwd, role, must):
        salt = hashlib.sha256((uid + pwd + "v802").encode("utf-8")).hexdigest()[:16]
        return {"display_name": name, "salt": salt, "password_hash": hp(pwd, salt), "role": role, "active": True, "must_change_password": must}
    users = {
        "diego": u("diego","Diego","tes2026","administrador",False),
        "anton": u("anton","Anton","1234","usuario",True),
        "melisa": u("melisa","Melisa","1111","usuario",True),
        "elvira": u("elvira","Elvira","2222","usuario",True),
        "lucia": u("lucia","Lucia","3333","usuario",True),
    }
    return {"schema_version":"8.02","updated_at":now_iso(),"users":users,"progress":{uid:{"answered":[],"wrong_ids":[],"correct_ids":[],"settings":{"daily_goal":148}} for uid in users}}

def ensure_store(store):
    base = default_store()
    store.setdefault("users", {})
    store.setdefault("progress", {})
    for uid, user in base["users"].items():
        store["users"].setdefault(uid, user)
    for uid in store["users"]:
        store["progress"].setdefault(uid, {"answered": [], "wrong_ids": [], "correct_ids": [], "settings": {"daily_goal": 148}})
        store["progress"][uid].setdefault("answered", [])
        store["progress"][uid].setdefault("wrong_ids", [])
        store["progress"][uid].setdefault("correct_ids", [])
        store["progress"][uid].setdefault("settings", {"daily_goal": 148})
    return store

def load_store():
    if USER_STORE_PATH.exists():
        try:
            return ensure_store(json.loads(USER_STORE_PATH.read_text(encoding="utf-8"))), "Archivo local"
        except Exception as exc:
            return default_store(), f"Nuevo por error: {exc}"
    store = default_store()
    save_store(store)
    return store, "Archivo local creado"

def save_store(store):
    try:
        store["updated_at"] = now_iso()
        USER_STORE_PATH.write_text(json.dumps(store, ensure_ascii=False, indent=2), encoding="utf-8")
        return True, "Guardado OK"
    except Exception as exc:
        return False, f"Error guardando: {exc}"

@st.cache_data(show_spinner=False)
def load_bank():
    raw = base64.b64decode(BANK_B64)
    with gzip.GzipFile(fileobj=io.BytesIO(raw), mode="rb") as gz:
        df = pd.read_csv(gz, dtype=str, encoding="utf-8-sig").fillna("")
    if "cuadro_aprendizaje" not in df.columns:
        df["cuadro_aprendizaje"] = df.get("tabla_esquema", "")
    df["respuesta_correcta"] = df["respuesta_correcta"].astype(str).str.upper().str.strip()
    return df[df["respuesta_correcta"].isin(["A","B","C","D"])].reset_index(drop=True)

def repair_user_password(store, uid, password):
    """Repara hash si el user_store quedó viejo/corrupto."""
    uid = uid.strip().lower()
    user = store.get("users", {}).get(uid)
    if not user:
        return None
    salt = hashlib.sha256((uid + password + "v802").encode("utf-8")).hexdigest()[:16]
    user["salt"] = salt
    user["password_hash"] = hp(password, salt)
    user["updated_at"] = now_iso()
    return user


def auth(store, uid, pwd):
    uid = uid.strip().lower()
    user = store.get("users", {}).get(uid)
    if not user or not user.get("active", False):
        return None

    # 1) Login normal con el hash actual del archivo.
    try:
        if hp(pwd, user["salt"]) == user["password_hash"]:
            return user
    except Exception:
        pass

    # 2) Rescate: si coincide con contraseña inicial, repara el usuario.
    if uid in INITIAL_PASSWORDS and pwd == INITIAL_PASSWORDS[uid]:
        repaired = repair_user_password(store, uid, pwd)
        save_store(store)
        return repaired

    return None

def progress(store, uid):
    ensure_store(store)
    return store["progress"][uid]

def opt(q, L):
    return n(q.get({"A":"opcion_a","B":"opcion_b","C":"opcion_c","D":"opcion_d"}[L], ""))

def why(q, L):
    return n(q.get(f"porque_no_{L.lower()}", ""))

def seen_ids(p):
    return {str(x.get("id","")) for x in p.get("answered", [])}



def ecg_override_table(q):
    blob = " ".join(n(q.get(k, "")) for k in ["enunciado","tema","subtema","conceptos_clave","opcion_a","opcion_b","opcion_c","opcion_d","explicacion"]).lower()
    if any(x in blob for x in ["ecg", "electrocardi", "onda t", "onda p", "qrs", "segmento st", "intervalo pr", "intervalo qt", "repolarización", "repolarizacion", "despolarización", "despolarizacion"]):
        return """### ECG básico para TES

| Elemento ECG | Qué representa | Regla de examen |
|---|---|---|
| Onda P | Despolarización auricular | La aurícula se activa |
| Complejo QRS | Despolarización ventricular | El ventrículo se activa; suele tapar la repolarización auricular |
| Onda T | Repolarización ventricular | El ventrículo se recupera eléctricamente |
| Segmento ST | Fase entre despolarización y repolarización ventricular | Vigilar elevación/depresión si procede |
| Intervalo PR | Conducción aurícula → nodo AV → ventrículo | Retraso/conducción AV |
| Intervalo QT | Despolarización + repolarización ventricular | Tiempo eléctrico ventricular total |

**Regla rápida:** P = aurícula se activa; QRS = ventrículo se activa; T = ventrículo se recupera."""
    return ""


def concept_override_table(q):
    blob = " ".join(n(q.get(k, "")) for k in ["enunciado","tema","subtema","conceptos_clave","opcion_a","opcion_b","opcion_c","opcion_d","explicacion"]).lower()
    if any(x in blob for x in ["medular", "cervical", "torácica", "toracica", "plexo braquial", "ambas piernas", "brazos conservados", "paraplej", "tetraplej"]):
        return """### Lesiones medulares por nivel: patrón TES

| Sospecha | Patrón motor/sensitivo esperado | Brazos | Piernas | Clave de examen |
|---|---|---:|---:|---|
| Lesión cervical alta | Déficit en brazos y piernas; puede comprometer respiración si es alta | Afectados | Afectadas | Tetraparesia/tetraplejia o alteración de cuatro extremidades |
| Lesión cervical baja | Déficit en brazos y piernas, a veces brazos parcialmente conservados según nivel | Afectados parcial/variable | Afectadas | Sigue siendo cervical si afecta miembros superiores |
| Lesión medular torácica | Déficit motor/sensitivo en tronco inferior y ambas piernas con brazos conservados | Conservados | Afectadas | Paraparesia/paraplejia: brazos normales + piernas alteradas |
| Lesión lumbar/conos/cauda equina | Déficit en piernas, esfínteres o sensibilidad en silla de montar | Conservados | Afectadas variable | Sospecha si hay alteración esfinteriana o perineal |
| Lesión cortical unilateral | Déficit de un lado del cuerpo, no patrón simétrico de ambas piernas | Variable | Variable | Hemicuerpo, cara/brazo/pierna de un lado |
| Plexo braquial | Déficit en brazo/hombro, no en ambas piernas | Afecta brazo | Conservadas | Lesión periférica de miembro superior |

**Regla de oro:** brazos conservados + ambas piernas afectadas = sospecha torácica o inferior; brazos afectados + piernas afectadas = sospecha cervical."""
    return ""



