def universal_concept_key(q):
    blob = " ".join(n(q.get(k, "")) for k in ["enunciado","tema","subtema","conceptos_clave","opcion_a","opcion_b","opcion_c","opcion_d","explicacion"]).lower()
    priority = ["ecg","medular","glasgow","start","stock","rcp","ictus","sepsis","abdomen","huesos","pma","norias","comunicaciones","planes"]
    for key in priority:
        if any(kw in blob for kw in CONCEPT_KEYWORDS.get(key, [])):
            return key
    return ""

def universal_concept_table(q):
    key = universal_concept_key(q)
    if key:
        return CONCEPT_TABLES.get(key, "")
    return ""



def personalized_failure_table(q, selected, correct):
    """Tabla personalizada para ESTA pregunta fallada."""
    selected_text = opt(q, selected)
    correct_text = opt(q, correct)
    concept = universal_concept_key(q) if "universal_concept_key" in globals() else ""
    tema = n(q.get("tema", ""))
    subtema = n(q.get("subtema", ""))
    enunciado = n(q.get("enunciado", ""))

    concept_names = {
        "ecg": "ECG / conducción eléctrica cardiaca",
        "medular": "lesión medular / localización neurológica",
        "glasgow": "escala de Glasgow",
        "start": "triaje START",
        "stock": "stock sanitario / FEFO-FIFO",
        "rcp": "RCP / DEA",
        "ictus": "Código Ictus",
        "sepsis": "sepsis / qSOFA",
        "abdomen": "anatomía abdominal",
        "huesos": "huesos por región anatómica",
        "planes": "planes / DRP / riesgo",
        "pma": "sectorización / PMA / PSA",
        "norias": "norias / evacuación",
        "comunicaciones": "comunicaciones operativas",
    }
    concept_label = concept_names.get(concept, f"{tema} / {subtema}".strip(" / "))

    selected_why = why(q, selected) or (
        f"{selected_text} pertenece a un contexto cercano, pero no responde al dato diferencial de este enunciado."
    )

    # Regla específica muy breve por concepto.
    rules = {
        "ecg": "P = aurícula; QRS = despolarización ventricular; T = repolarización ventricular.",
        "medular": "Brazos conservados + ambas piernas afectadas = torácica/inferior; brazos afectados = cervical.",
        "glasgow": "Calcula ocular + verbal + motora; no confundas retira dolor con localiza dolor.",
        "start": "Aplica START en orden: camina, respira, perfusión, órdenes.",
        "stock": "Si manda caducidad usa FEFO; si manda entrada usa FIFO.",
        "rcp": "No responde y no respira normal = activar ayuda y comenzar RCP.",
        "ictus": "Déficit focal súbito + hora de inicio = sospecha/activación ictus.",
        "sepsis": "Infección + deterioro fisiológico = sospecha sepsis; qSOFA orienta gravedad.",
        "abdomen": "Localización abdominal orienta órgano y riesgo.",
        "huesos": "Distingue región: brazo ≠ antebrazo; muslo ≠ pierna.",
        "planes": "Riesgo = probabilidad + daño + vulnerabilidad; si cambia escenario, reevalúa.",
        "pma": "Seguridad → sectorización → triaje → estabilización → evacuación.",
        "norias": "Evacuar bien = circuito regulado, prioridad clara y centro útil.",
        "comunicaciones": "Mensaje operativo = quién, dónde, qué pasa, prioridad y confirmación.",
    }
    specific_rule = rules.get(concept, n(q.get("regla_oro", "")) or "Dato diferencial → criterio técnico → respuesta.")

    st.markdown("### Tabla personalizada de este fallo")
    st.markdown(f"""
| Qué debes comparar | En esta pregunta |
|---|---|
| Concepto real que estás entrenando | **{concept_label}** |
| Dato clave del enunciado | {enunciado} |
| Tu respuesta | **{selected}. {selected_text}** |
| Por qué te llevó al fallo | {selected_why} |
| Respuesta correcta | **{correct}. {correct_text}** |
| Regla que debes memorizar | {specific_rule} |
| Cómo evitar repetirlo | Antes de elegir, pregunta: “¿qué dato exacto del enunciado activa la respuesta?” |
""")

    # Microtablas 100% específicas para conceptos donde el alumno necesita discriminación fina.
    if concept == "ecg":
        st.markdown("### Microtabla específica ECG")
        st.markdown("""
| Si te preguntan... | Responde... | No lo confundas con... |
|---|---|---|
| Onda P | Despolarización auricular | QRS u onda T |
| QRS | Despolarización ventricular | Onda T |
| Onda T | Repolarización ventricular | Despolarización ventricular |
| Sístole | Fenómeno mecánico | Onda eléctrica |
""")
    elif concept == "medular":
        st.markdown("### Microtabla específica lesión medular")
        st.markdown("""
| Patrón del caso | Sospecha mejor |
|---|---|
| Brazos y piernas afectados | Cervical |
| Brazos conservados + ambas piernas afectadas | Torácica o inferior |
| Piernas + esfínteres/silla de montar | Lumbar/conos/cauda equina |
| Un hemicuerpo | Cortical unilateral |
| Solo brazo/hombro | Plexo braquial |
""")
    elif concept == "glasgow":
        st.markdown("### Microtabla específica Glasgow")
        st.markdown("""
| Componente | Máximo | Clave que más se confunde |
|---|---:|---|
| Ocular | 4 | espontánea 4, habla 3, dolor 2, ninguna 1 |
| Verbal | 5 | orientado 5, confuso 4, palabras inapropiadas 3 |
| Motora | 6 | localiza dolor 5, retira dolor 4 |
""")
    elif concept == "start":
        st.markdown("### Microtabla específica START")
        st.markdown("""
| Hallazgo | Color |
|---|---|
| Camina | Verde inicial |
| No respira tras abrir vía aérea | Negro |
| Respira tras abrir vía aérea | Rojo |
| FR > 30 | Rojo |
| No obedece órdenes | Rojo |
| Estable no ambulante | Amarillo |
""")


def render_failure(q, selected, correct):
    st.markdown("## 🚨 Aprendizaje obligatorio del fallo")
    st.markdown(f"### Correcta: **{correct}. {opt(q, correct)}**")
    st.markdown(f"**Tu respuesta:** {selected}. {opt(q, selected)}")

    personalized_failure_table(q, selected, correct)

    table = universal_concept_table(q) or n(q.get("cuadro_aprendizaje", "")) or n(q.get("tabla_esquema", ""))
    if table:
        st.markdown("### Tabla de apoyo del concepto")
        st.markdown(table)

    st.markdown("### Explicación")
    st.markdown(n(q.get("explicacion", "")) or "La clave es aplicar el criterio técnico exacto del caso.")

    st.markdown("### Por qué fallaste")
    st.markdown(why(q, selected) or f"{opt(q, selected)} es plausible, pero no encaja con el dato diferencial. Aquí manda {opt(q, correct)}.")

    st.markdown("### Descarte de distractores")
    hay = False
    for L in ["A","B","C","D"]:
        if L != correct:
            txt = why(q, L)
            if txt:
                hay = True
                st.write(f"- **{L}. {opt(q,L)}:** {txt}")
    if not hay:
        for L in ["A","B","C","D"]:
            if L != correct:
                st.write(f"- **{L}. {opt(q,L)}:** distractor cercano, pero no cumple el criterio exacto.")

    st.markdown("### Regla de oro")
    st.markdown(n(q.get("regla_oro", "")) or "Dato diferencial → criterio técnico → respuesta.")

    st.markdown("### Error típico")
    st.markdown(n(q.get("error_tipico", "")) or "Elegir por familiaridad sin comprobar el contexto exacto.")

    st.markdown("### Tip de examen")
    st.markdown(n(q.get("tip_examen", "")) or "Subraya cifras, fase, zona, estructura o signo clínico.")

    st.markdown("### Mini-lección")
    st.markdown(n(q.get("minileccion", "")) or "Concepto → criterio → caso → trampa habitual.")

    mn = n(q.get("mnemotecnia", ""))
    if mn:
        st.markdown("### Mnemotecnia")
        st.markdown(mn)

def init():
    defaults = {
        "store": None, "store_mode": "", "logged": False, "uid": "", "display_name": "", "role": "",
        "queue_key": "", "queue": [], "queue_pos": 0, "answered": False, "selected": None,
        "current_qid": "", "last_save": ""
    }
    for k, v in defaults.items():
        st.session_state.setdefault(k, v)

def _answer_stats(p):
    """Calcula estadísticas de repaso sin romper user_store antiguos."""
    answered = p.get("answered", []) or []
    stats = {}
    weak_topics = {}
    for e in answered:
        qid = str(e.get("id", ""))
        if not qid:
            continue
        s = stats.setdefault(qid, {"attempts": 0, "fails": 0, "last_ok": None, "last_ts": ""})
        s["attempts"] += 1
        ok = int(e.get("correcta", 0) or 0) == 1
        s["last_ok"] = ok
        s["last_ts"] = e.get("timestamp", "")
        if not ok:
            s["fails"] += 1
            topic = (e.get("tema", "") or e.get("subtema", "") or "").strip()
            if topic:
                weak_topics[topic] = weak_topics.get(topic, 0) + 1
    return stats, weak_topics

def _age_days(ts):
    try:
        return max((datetime.now(timezone.utc) - datetime.fromisoformat(str(ts).replace("Z", "+00:00"))).days, 0)
    except Exception:
        return 0

def diversify_queue(ids, df, max_same_tema=1, max_same_modulo=2, cooldown_subtema=22):
    """Ordena la cola para estudiar sin rachas largas del mismo bloque.

    - Si estudias todo junto, intenta alternar asignaturas.
    - Si estudias una asignatura, alterna temas y subtemas.
    - Evita encadenar preguntas prácticamente idénticas del mismo subtema.
    """
    if not ids:
        return ids
    meta = df.set_index(df["id"].astype(str))[["modulo", "tema", "subtema"]].to_dict("index") if not df.empty else {}
    remaining = list(ids)
    result = []
    recent_sub = []
    same_tema_run = 0
    same_modulo_run = 0
    last_tema = None
    last_modulo = None
    guard = 0
    while remaining and guard < len(ids) * 4:
        guard += 1
        chosen_idx = None
        for idx, qid in enumerate(remaining):
            m = meta.get(str(qid), {})
            modulo = str(m.get("modulo", ""))
            tema = str(m.get("tema", ""))
            subtema = str(m.get("subtema", ""))
            if subtema and subtema in recent_sub:
                continue
            if tema and tema == last_tema and same_tema_run >= max_same_tema:
                continue
            if modulo and modulo == last_modulo and same_modulo_run >= max_same_modulo:
                continue
            chosen_idx = idx
            break
        if chosen_idx is None:
            for idx, qid in enumerate(remaining):
                m = meta.get(str(qid), {})
                tema = str(m.get("tema", ""))
                subtema = str(m.get("subtema", ""))
                if subtema and subtema in recent_sub:
                    continue
                if tema and tema == last_tema and same_tema_run >= max_same_tema:
                    continue
                chosen_idx = idx
                break
        if chosen_idx is None:
            chosen_idx = 0
        qid = remaining.pop(chosen_idx)
        m = meta.get(str(qid), {})
        modulo = str(m.get("modulo", ""))
        tema = str(m.get("tema", ""))
        subtema = str(m.get("subtema", ""))
        same_tema_run = same_tema_run + 1 if tema == last_tema else 1
        same_modulo_run = same_modulo_run + 1 if modulo == last_modulo else 1
        last_tema = tema
        last_modulo = modulo
        result.append(qid)
        if subtema:
            recent_sub.append(subtema)
            recent_sub = recent_sub[-cooldown_subtema:]
    result.extend(remaining)
    return result

def apply_study_filters(df, selected_modules, selected_tema, selected_subtema):
    """Filtra el banco sin borrar nada: todo junto, por asignaturas o por bloques."""
    work = df.copy()
    if selected_modules:
        work = work[work["modulo"].isin(selected_modules)]
    if selected_tema != "Todos los temas":
        work = work[work["tema"] == selected_tema]
    if selected_subtema != "Todos los subtemas":
        work = work[work["subtema"] == selected_subtema]
    return work.reset_index(drop=True)

def build_queue(df, p, mode):
    work = df.copy()

    seen = seen_ids(p)
    wrong = set(p.get("wrong_ids", []))
    stats, weak_topics = _answer_stats(p)

    if mode == "Solo no respondidas":
        work = work[~work["id"].astype(str).isin(seen)]
        ids = work["id"].astype(str).tolist()
        random.shuffle(ids)
        return diversify_queue(ids, df)

    if mode == "Solo mis fallos":
        work = work[work["id"].astype(str).isin(wrong)]
        ids = work["id"].astype(str).tolist()
        random.shuffle(ids)
        return diversify_queue(ids, df)

    if mode == "Alta/filtro_10":
        work = work[work["nivel_dificultad"].str.lower().str.contains("alta|filtro_10", na=False)]
        ids = work["id"].astype(str).tolist()
        random.shuffle(ids)
        return diversify_queue(ids, df)

    if mode == "Libre":
        ids = work["id"].astype(str).tolist()
        random.shuffle(ids)
        return diversify_queue(ids, df)

    # Plan de hoy optimizado: fallos primero, luego conceptos débiles, nuevas, alta dificultad y repasos antiguos.
    scored = []
    for _, row in work.iterrows():
        qid = str(row.get("id", ""))
        tema = n(row.get("tema", ""))
        subtema = n(row.get("subtema", ""))
        dif = n(row.get("nivel_dificultad", "")).lower()
        s = stats.get(qid, {})
        score = random.random()
        if qid in wrong:
            score += 10000
        if s.get("fails", 0):
            score += 1200 * int(s.get("fails", 0))
        if tema in weak_topics:
            score += 250 * weak_topics.get(tema, 0)
        if subtema in weak_topics:
            score += 250 * weak_topics.get(subtema, 0)
        if qid not in seen:
            score += 3000
        if "alta" in dif or "filtro_10" in dif:
            score += 900
        if qid in seen and s.get("last_ok"):
            days = _age_days(s.get("last_ts", ""))
            if days >= 7:
                score += 700
            elif days >= 3:
                score += 300
            else:
                score -= 500
        scored.append((score, qid))
    scored.sort(reverse=True)
    return diversify_queue([qid for _, qid in scored], df)


def get_q(df, qid):
    row = df[df["id"].astype(str) == str(qid)]
    if row.empty:
        return None
    return row.iloc[0]

def login_page():
    st.title("🚑 TES Leixa — Acceso")
    st.caption(VERSION)
    st.info(f"Guardado: {st.session_state.store_mode}")

    with st.expander("Usuarios iniciales"):
        st.write("diego / tes2026 → administrador")
        st.write("anton / 1234")
        st.write("melisa / 1111")
        st.write("elvira / 2222")
        st.write("lucia / 3333")

    uid = st.text_input("Usuario")
    pwd = st.text_input("Contraseña", type="password")

    if st.button("Entrar", use_container_width=True):
        user = auth(st.session_state.store, uid, pwd)
        if user:
            clean = uid.strip().lower()
            st.session_state.logged = True
            st.session_state.uid = clean
            st.session_state.display_name = user.get("display_name", clean)
            st.session_state.role = user.get("role", "usuario")
            ok, msg = save_store(st.session_state.store)
            st.session_state.last_save = msg
            st.rerun()
        else:
            st.error("Usuario o contraseña incorrectos.")

    st.divider()
    if st.button("Restablecer usuarios iniciales", use_container_width=True):
        st.session_state.store = default_store()
        ok, msg = save_store(st.session_state.store)
        st.session_state.store_mode = "Archivo local reiniciado"
        st.session_state.last_save = msg
        st.success("Usuarios restablecidos. Ahora entra con diego / tes2026.")
        st.rerun()

def main_page():
    df = load_bank()
    store = st.session_state.store
    p = progress(store, st.session_state.uid)

    st.title("🚑 TES Leixa — Test táctil")
    st.caption(VERSION)

    total = len(df)
    seen_all = seen_ids(p)

    with st.sidebar:
        st.write(f"Usuario: **{st.session_state.display_name}**")
        st.write(f"Guardado: **{st.session_state.store_mode}**")
        st.write(f"Último guardado: {st.session_state.last_save}")
        mode = st.radio("Modo", ["Plan de hoy", "Solo no respondidas", "Solo mis fallos", "Alta/filtro_10", "Libre"])

        st.markdown("### Filtro de estudio")
        all_modules = sorted([x for x in df["modulo"].unique() if str(x).strip()])
        scope = st.radio("Asignaturas", ["Todo junto", "Elegir asignaturas"], horizontal=True)
        if scope == "Todo junto":
            selected_modules = all_modules
        else:
            selected_modules = st.multiselect(
                "Asignaturas a estudiar",
                all_modules,
                default=all_modules,
                help="Puedes elegir una, varias o todas. No borra preguntas; solo filtra el bloque actual."
            )
            if not selected_modules:
                selected_modules = all_modules

        temas_disponibles = sorted([x for x in df[df["modulo"].isin(selected_modules)]["tema"].unique() if str(x).strip()])
        selected_tema = st.selectbox("Bloque / tema", ["Todos los temas"] + temas_disponibles)

        sub_base = df[df["modulo"].isin(selected_modules)]
        if selected_tema != "Todos los temas":
            sub_base = sub_base[sub_base["tema"] == selected_tema]
        subtemas_disponibles = sorted([x for x in sub_base["subtema"].unique() if str(x).strip()])
        selected_subtema = st.selectbox("Subbloque / subtema", ["Todos los subtemas"] + subtemas_disponibles)

        filtered_df = apply_study_filters(df, selected_modules, selected_tema, selected_subtema)
        st.caption(f"Filtro activo: {len(filtered_df)} preguntas")

        if st.button("Nuevo bloque"):
            st.session_state.queue_key = ""
            st.session_state.queue = []
            st.session_state.queue_pos = 0
            st.session_state.answered = False
            st.session_state.current_qid = ""
            st.rerun()
        if st.button("Cerrar sesión"):
            st.session_state.logged = False
            st.rerun()

    filtered_seen = len(set(filtered_df["id"].astype(str)).intersection(seen_all)) if not filtered_df.empty else 0
    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Banco total", total)
    c2.metric("Filtro activo", len(filtered_df))
    c3.metric("Vistas en filtro", filtered_seen)
    c4.metric("Fallos pendientes", len(p.get("wrong_ids", [])))

    with st.expander("Distribución del filtro", expanded=False):
        if filtered_df.empty:
            st.warning("El filtro actual no tiene preguntas. Cambia asignatura, tema o subtema.")
        else:
            dist = filtered_df.groupby(["modulo", "tema"]).size().reset_index(name="preguntas").sort_values(["modulo", "preguntas"], ascending=[True, False])
            st.dataframe(dist, use_container_width=True, hide_index=True)

    qkey = f"{mode}|{','.join(selected_modules)}|{selected_tema}|{selected_subtema}"
    if st.session_state.queue_key != qkey or not st.session_state.queue:
        st.session_state.queue_key = qkey
        st.session_state.queue = build_queue(filtered_df, p, mode)
        st.session_state.queue_pos = 0
        st.session_state.answered = False
        st.session_state.current_qid = ""
        st.session_state.selected = None

    if not st.session_state.queue or st.session_state.queue_pos >= len(st.session_state.queue):
        st.success("Bloque terminado o sin preguntas.")
        return

    qid = st.session_state.queue[st.session_state.queue_pos]
    q = get_q(df, qid)
    if q is None:
        st.session_state.queue_pos += 1
        st.rerun()
        return

    correct = n(q.get("respuesta_correcta")).upper()

    st.divider()
    st.write(f"**Pregunta {st.session_state.queue_pos + 1} de {len(st.session_state.queue)}**")
    st.caption(f"{n(q.get('id'))} · {n(q.get('modulo'))} · {n(q.get('tema'))} · {n(q.get('nivel_dificultad'))}")
    st.markdown(f"### {n(q.get('enunciado'))}")

    if st.session_state.answered and st.session_state.current_qid == qid:
        selected = st.session_state.selected
        if selected == correct:
            st.success("Correcto. No entra en repaso de fallos.")
        else:
            st.error(f"Incorrecto. Correcta: {correct}. {opt(q, correct)}")
            st.warning("Queda en 'Solo mis fallos'.")
            render_failure(q, selected, correct)

        if st.button("Siguiente pregunta", use_container_width=True):
            st.session_state.queue_pos += 1
            st.session_state.answered = False
            st.session_state.selected = None
            st.session_state.current_qid = ""
            st.rerun()
        return

    for L in ["A","B","C","D"]:
        if st.button(f"{L}. {opt(q,L)}", key=f"answer_{qid}_{L}", use_container_width=True):
            selected = L
            is_ok = selected == correct
            entry = {"timestamp": now_iso(), "id": qid, "modulo": n(q.get("modulo")), "tema": n(q.get("tema")),
                     "subtema": n(q.get("subtema")), "dificultad": n(q.get("nivel_dificultad")),
                     "respuesta_usuario": selected, "respuesta_correcta": correct, "correcta": int(is_ok)}
            p["answered"].append(entry)
            if is_ok:
                if qid not in p["correct_ids"]:
                    p["correct_ids"].append(qid)
                if qid in p["wrong_ids"]:
                    p["wrong_ids"].remove(qid)
            else:
                if qid not in p["wrong_ids"]:
                    p["wrong_ids"].append(qid)
            ok, msg = save_store(store)
            st.session_state.last_save = msg
            st.session_state.answered = True
            st.session_state.selected = selected
            st.session_state.current_qid = qid
            st.rerun()

init()
if st.session_state.store is None:
    st.session_state.store, st.session_state.store_mode = load_store()
if not st.session_state.logged:
    login_page()
else:
    main_page()
